{
  "mode": "method",
  "tests": [
    {
      "name": "search_controller_valid_query",
      "input": {
        "query": "topcoder"
      },
      "output": {
        "results": [
          {
            "id": 1,
            "username": "topcoder_user",
            "status": "active"
          }
        ]
      },
      "notes": "Valid query should return expected user data."
    },
    {
      "name": "search_controller_empty_query",
      "input": {
        "query": ""
      },
      "output": {
        "results": []
      },
      "notes": "Empty query should return no results."
    },
    {
      "name": "statistics_controller_valid_user",
      "input": {
        "userId": 1
      },
      "output": {
        "statistics": {
          "projects": 5,
          "challenges": 10
        }
      },
      "notes": "Valid user ID should return correct statistics."
    },
    {
      "name": "statistics_controller_invalid_user",
      "input": {
        "userId": 9999
      },
      "output": {
        "error": "User not found"
      },
      "notes": "Invalid user ID should return an error."
    },
    {
      "name": "search_controller_special_characters",
      "input": {
        "query": "!@#$%^&*()"
      },
      "output": {
        "results": []
      },
      "notes": "Special characters should return no results."
    },
    {
      "name": "search_controller_case_insensitivity",
      "input": {
        "query": "TopCoder"
      },
      "output": {
        "results": [
          {
            "id": 1,
            "username": "topcoder_user",
            "status": "active"
          }
        ]
      },
      "notes": "Search should be case insensitive."
    },
    {
      "name": "statistics_controller_no_statistics",
      "input": {
        "userId": 2
      },
      "output": {
        "statistics": {
          "projects": 0,
          "challenges": 0
        }
      },
      "notes": "User with no statistics should return zero values."
    },
    {
      "name": "search_controller_long_query",
      "input": {
        "query": "a".repeat(256)
      },
      "output": {
        "error": "Query too long"
      },
      "notes": "Long queries should be handled gracefully."
    }
  ],
  "assumptions": "All tests assume the database is seeded with known data for consistency.",
  "notes": "Ensure all tests are run in a clean environment to avoid state issues."
}
